public int countHomogenous(String s) {
    final int MOD = 1000000007;
    long count = 1;
    long total = 0;
    for (int i = 1; i < s.length(); ++i) {
        count = (s.charAt(i) == s.charAt(i - 1)) ? count + 1 : 1;
        total = (total + count) % MOD;
    }
    return (int) (total + count) % MOD;
}
